import{A as t}from"./chunks/ArticleCardList.ZIPwxxHA.js";import{g as r,h as s,S as i,z as o,l as n}from"./chunks/vitepress-theme-teek.DYsc1jHb.js";const a=[{title:"产品观察与拆解分析",icon:"🔍",color:"#6366f1",articles:[{title:"AI-powered 搜索引擎观察分析：Perplexity 与知识工作者",url:"/product-sense/perplexity-knowledge-worker",description:"从产品 Sense 与工程逻辑的双重视角，深入分析 Perplexity 如何重新定义搜索体验."}]},{title:"新 T 型人：AI 时代的复合型人才",icon:"🌟",color:"#8b5cf6",articles:[{title:"AI 原生时代的复合型人才，究竟需要怎样的特质？",url:"/product-sense/ai-native-composite-talents/",description:"一篇阅读 Paul Graham 深度长文后的思考，探寻 AI 时代下跨界能力的构建路径。"},{title:'当"实现"不再是壁垒：工程师如何构建 Product Sense？',url:"/product-sense/engineer-build-product-sense",description:"工程师视角下的产品思维构建指南——将抽象的 产品 Sense 解构为三个核心数学公式，并提供一套基于“逆向工程”的刻意练习指南，助力开发者在算力过剩的时代，完成从“代码工匠”到“价值创造者”的认知跃迁。"}]},{title:"产品创造与商业化",icon:"💡",color:"#f59e0b",articles:[{title:"放弃增长执念，为什么“小而美”才是可持续之路？",url:"/product-sense/small-rule-learn",description:"本文结合《小而美：持续盈利的经营法则》书中提出的一种不同的商业视角：企业存在的首要目的不是为了融资和扩张，而是为了通过解决问题来获得持续的盈利。从自身的研发视角，把将这本书背后的经营逻辑与产品哲学梳理为几个核心层面的思考"},{title:"好书籍汇总与推荐",url:"/growth/books#_2-产品与商业",description:"系统整理了产品 Sense 与创造、商业化相关的必读书籍清单，便于开发者和产品经理学习和应用产品 Sense 的理论和实践。"}]},{title:"方法论学习与总结：洞察力与经济学思维",icon:"📊",color:"#10b981",articles:[{title:"洞察力模型：如何看透产品与技术背后的系统逻辑？",url:"/product-sense/insight-model",description:"用通俗易懂的方式，带你拆解一套实用的洞察力模型，让我们学会透过现象抓住本质，建立透过现象看本质的思维框架，从根源上解决问题。"},{title:"用经济学思维做产品",url:"/product-sense/using-economics-thinking",description:"通过拆解日常生活中的经典案例，提炼成本收益、博弈均衡、有限理性、效率改进等核心经济学原理，并系统地将其应用到产品生命周期的核心环节——定义定位、定价策略、体验锁定及生态构建。"}]}],g=JSON.parse('{"title":"学习与实践全景","description":"产品 Sense 学习与实践全景一览，涵盖 AI 产品观察、复合型人才成长、商业化思考及方法论总结等。","frontmatter":{"date":"2026-03-19T23:05:50.000Z","title":"学习与实践全景","description":"产品 Sense 学习与实践全景一览，涵盖 AI 产品观察、复合型人才成长、商业化思考及方法论总结等。","categories":["产品 Sense","AI"],"coverImg":"https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/product_sense_bg.png","permalink":"/product-sense"},"headers":[],"relativePath":"10.产品 Sense/00.学习与实践全景.md","filePath":"10.产品 Sense/00.学习与实践全景.md"}'),l={name:"10.产品 Sense/00.学习与实践全景.md"},m=Object.assign(l,{setup(c){return(d,e)=>(s(),r("div",null,[e[0]||(e[0]=i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /10.产品 Sense/00.学习与实践全景.md for this page in Markdown format</div><h1 id="学习与实践全景" tabindex="-1">学习与实践全景 <a class="header-anchor" href="#学习与实践全景" aria-label="Permalink to “学习与实践全景”">​</a></h1><blockquote><p>产品 Sense 的精髓在于<strong>用最小投入撬动最大价值，同时精准洞察人性</strong>：</p><ul><li><strong>追求高杠杆</strong>——以极简技术解决复杂问题，拒绝为炫技而设计的伪需求；</li><li><strong>平衡感性与理性</strong>——既共情用户的真实场景与情绪，又冷静追溯痛点本质，让产品既有温度，又不至于沦为功能的堆砌。</li></ul></blockquote><p>解构这种产品 Sense 的<strong>基础在于对投入产出比（ROI）的极致追求与对人性的深度剖析</strong>：</p><ul><li>一方面，<strong>卓越的产品嗅觉意味着寻找“高杠杆解”</strong>，用最克制的技术复杂度去撬动最广泛且强烈的用户价值，果断规避为了技术而技术的伪需求陷阱。</li><li>另一方面，既需要<strong>设身处地感知用户的真实使用场景与情绪，又必须保持理性去追问痛点的根源</strong>，确保产品既不沦为臃肿的需求许愿池，也不变成缺乏人性温度的冰冷机器。</li></ul><img src="https://insight-stack-1252300811.cos.ap-shanghai.myqcloud.com/img/cover/product_sense_bg.png" style="width:100%;border-radius:8px;margin-bottom:20px;" alt="about site background"><p>在产品成功率不足 10% 的残酷市场中，产品 Sense 往往被误认为是某种不可复制的玄妙“直觉”。然而，它本质上是一套可拆解、可训练的思维模式，核心在于：在信息不完整、资源受限的环境下，依然能精准判断“做什么”与“不做什么”，从而确保团队在投入开发前始终是在“做对产品”。</p><h2 id="_2-精选专题" tabindex="-1">2.精选专题 <a class="header-anchor" href="#_2-精选专题" aria-label="Permalink to “2.精选专题”">​</a></h2>',8)),o(t,{categories:n(a)},null,8,["categories"])]))}});export{g as __pageData,m as default};
